import { Command }  from 'commander';
import { Registry } from '../../registry/Registry.js';

export function drawErrorsCommand(program: Command): void {
  program
    .command('drawErrors')
    .description('List all registered errors (key + message)')
    .action(() => {
      const records = Registry.getInstance().getAll();

      if (records.length === 0) {
        console.log('No errors registered.');
        return;
      }

      const keyWidth = 55;
      console.log('KEY'.padEnd(keyWidth) + 'MESSAGE');

      for (const r of records) {
        const shortKey = r.key.length > keyWidth
          ? '…' + r.key.slice(-(keyWidth - 1))
          : r.key;
        console.log(shortKey.padEnd(keyWidth) + r.message);
      }
    });
}
